import pandas as pd
import matplotlib.pyplot as plt
import matplotlib.patches as mpatches
import os

# load the output generated by the C++ program
# assumes working directory is the repo root

def main():
    # Enable LaTeX rendering for consistent math fonts
    plt.rcParams['text.usetex'] = True
    plt.rcParams['font.family'] = 'serif'
    plt.rcParams['font.size'] = 10
    plt.rcParams['axes.labelsize'] = 11
    plt.rcParams['axes.titlesize'] = 11
    plt.rcParams['legend.fontsize'] = 9
    plt.rcParams['xtick.labelsize'] = 9
    plt.rcParams['ytick.labelsize'] = 9
    
    # Mature, muted color palette for academic publications
    colors = {
        'unpooled': '#1f77b4',  # steel blue
        'pooled': '#d62728',    # brick red
        'eb': '#ff7f0e'         # burnt orange
    }
    
    # Distinct line styles for grayscale accessibility
    linestyles = {
        'unpooled': '-',      # solid
        'pooled': '-',        # solid
        'eb': '-'             # solid
    }
    
    # read the CSV produced by the C++ program
    df = pd.read_csv("regret_scenarios.csv")

    # group by scenario keys - preserve original order from CSV (no sorting)
    groups = df.groupby(["n", "mu2", "tau", "sigma"], sort=False)
    # fixed 4x2 layout, sized for double-column format
    rows = 2
    cols = 5
    fig, axes = plt.subplots(rows, cols, figsize=(13, 6.5), squeeze=False)

    idx = 0
    for (key, g) in groups:
        r = idx // cols
        c = idx % cols
        ax = axes[r][c]
        t = g.t.values
        
        # Plot with colorblind-safe colors, solid lines, with transparency to see overlaps
        # Plot in reverse order so unpooled is on top
        ax.plot(t, g.mean_eb.values, label='EB', 
                color=colors['eb'], linestyle=linestyles['eb'], linewidth=1.8, alpha=0.95)
        ax.fill_between(t,
                        g.mean_eb - 1.96 * g.se_eb,
                        g.mean_eb + 1.96 * g.se_eb,
                        color=colors['eb'], alpha=0.15)

        ax.plot(t, g.mean_pooled.values, label='Pooled TS', 
                color=colors['pooled'], linestyle=linestyles['pooled'], linewidth=1.8, alpha=0.95)
        ax.fill_between(t,
                        g.mean_pooled - 1.96 * g.se_pooled,
                        g.mean_pooled + 1.96 * g.se_pooled,
                        color=colors['pooled'], alpha=0.15)
        
        ax.plot(t, g.mean_unpooled.values, label='Unpooled TS', 
                color=colors['unpooled'], linestyle=linestyles['unpooled'], linewidth=1.8, alpha=0.95)
        ax.fill_between(t,
                        g.mean_unpooled - 1.96 * g.se_unpooled,
                        g.mean_unpooled + 1.96 * g.se_unpooled,
                        color=colors['unpooled'], alpha=0.15)

        ax.set_title(rf"$n={key[0]}, \mu_2={key[1]}, \tau={key[2]}, \sigma^2={key[3]**2:.2f}$")
        ax.set_xlabel('Time step')
        ax.set_ylabel('Cumulative regret')
        
        # Determine which algorithm had lowest final regret
        final_unpooled = g.mean_unpooled.values[-1]
        final_pooled = g.mean_pooled.values[-1]
        final_eb = g.mean_eb.values[-1]
        
        min_regret = min(final_unpooled, final_pooled, final_eb)
        if min_regret == final_unpooled:
            winner = 'Unpooled TS'
            winner_color = colors['unpooled']
        elif min_regret == final_pooled:
            winner = 'Pooled TS'
            winner_color = colors['pooled']
        else:
            winner = 'EB'
            winner_color = colors['eb']
        
        # Add text at top left of subplot
        ax.text(0.02, 0.98, f'Lowest: {winner}', 
                transform=ax.transAxes, fontsize=8,
                verticalalignment='top', horizontalalignment='left',
                bbox=dict(boxstyle='round', facecolor='#f5f5f5', alpha=1.0, edgecolor='#cccccc'))
        
        idx += 1

    # hide unused subplots
    for k in range(idx, rows*cols):
        r = k // cols
        c = k % cols
        axes[r][c].set_visible(False)

    # get number of runs from first scenario (all have same runs)
    first_scenario = list(groups)[0][1]
    # Note: runs info isn't in CSV, but we can infer from the number or hardcode
    # For now, let's add it to the title assuming 500 runs based on the C++ code
    
    # add priors and runs centered at top with more spacing
    fig.text(0.5, 0.99, r"Priors: $\mu_0 = [0, 0]$, $\tau_0 = [1, 1]$", 
             fontsize=10, va='top', ha='center')
    fig.text(0.5, 0.965, r"Runs: 500", 
             fontsize=10, va='top', ha='center')
    
    # add parameter key as centered text at bottom
    key_text = (r"$\mu_2$ = true difference, "
                r"$\sigma^2$ = within-person variance, " 
                r"$\tau^2$ = between-person variance")
    fig.text(0.5, 0.05, key_text, fontsize=9, va='top', ha='center')
    
    # add algorithm legend below parameter key, centered
    from matplotlib.lines import Line2D
    legend_elements = [
        Line2D([0], [0], color=colors['unpooled'], linewidth=1.2, label='Unpooled TS'),
        Line2D([0], [0], color=colors['pooled'], linewidth=1.2, label='Pooled TS'),
        Line2D([0], [0], color=colors['eb'], linewidth=1.2, label='EB')
    ]
    fig.legend(handles=legend_elements, loc='upper center', bbox_to_anchor=(0.5, 0.035),
               fontsize=9, framealpha=1.0, facecolor='#f5f5f5', edgecolor='#cccccc', ncol=3)
    
    plt.tight_layout(rect=[0, 0.05, 1, 0.96])
    plt.savefig("plots/regret.png", dpi=150, bbox_inches='tight')
    print("Saved plot to plots/regret.png")
    plt.show()

if __name__ == "__main__":
    main()
